// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

export default function Radar({ center = [33.749, -84.388], zoom = 6, height = "60vh" }) {
  const mapRef = useRef(null);
  const layerRef = useRef(null);
  const [frames, setFrames] = useState([]); // unix seconds
  const [idx, setIdx] = useState(0);

  // fetch RainViewer timeline (past + forecast frame timestamps)
  async function loadTimeline() {
    const res = await fetch("https://api.rainviewer.com/public/weather-maps.json");
    const json = await res.json();
    // past + nowcast; prefer past first then forecast
    const seq = [
      ...(json.radar?.past ?? []),
      ...(json.radar?.nowcast ?? []),
    ].map(f => f.time);
    setFrames(seq);
    setIdx(seq.length - 1);
  }

  useEffect(() => {
    if (!mapRef.current) {
      const map = L.map("rv-map", { zoomControl: true, attributionControl: true }).setView(center, zoom);
      mapRef.current = map;
      L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
        maxZoom: 18,
        attribution: "© OpenStreetMap",
      }).addTo(map);
      loadTimeline();
    } else {
      mapRef.current.setView(center, zoom);
    }
    // cleanup on unmount
    return () => {};
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (!mapRef.current || frames.length === 0) return;

    const time = frames[idx];
    const url = `https://tilecache.rainviewer.com/v2/radar/${time}/256/{z}/{x}/{y}/2/1_1.png`;

    if (layerRef.current) {
      layerRef.current.setUrl(url);
      return;
    }
    layerRef.current = L.tileLayer(url, {
      opacity: 0.7,
      zIndex: 50,
    }).addTo(mapRef.current);
  }, [frames, idx]);

  const onPrev = () => setIdx(i => Math.max(0, i - 1));
  const onNext = () => setIdx(i => Math.min(frames.length - 1, i + 1));

  const label = useMemo(() => {
    if (!frames.length) return "Loading…";
    const d = new Date(frames[idx] * 1000);
    return d.toUTCString().replace("GMT", "UTC");
  }, [frames, idx]);

  return (
    <div className="w-full">
      <div id="rv-map" style={{ width: "100%", height }} />
      <div className="mt-2 flex items-center gap-3">
        <button
          onClick={onPrev}
          className="px-3 py-1 rounded-xl bg-black/40 text-white hover:bg-black/60"
          disabled={!frames.length || idx === 0}
        >
          ◀
        </button>
        <input
          type="range"
          min={0}
          max={Math.max(0, frames.length - 1)}
          value={idx}
          onChange={(e) => setIdx(parseInt(e.target.value, 10))}
          className="w-full"
        />
        <button
          onClick={onNext}
          className="px-3 py-1 rounded-xl bg-black/40 text-white hover:bg-black/60"
          disabled={!frames.length || idx === frames.length - 1}
        >
          ▶
        </button>
        <span className="text-xs opacity-80">{label}</span>
      </div>
    </div>
  );
}
